sys_script.script:
(function executeRule(current, previous /*null when async*/ ) {

    var REQUESTER_FIELD = 'requester';
    var TABLE_NAME = 'x_1839224_chroma_0_chromatech_customer_queries';
    var LIMIT = 7;

    var requester = current.getValue(REQUESTER_FIELD);
    if (!requester) {
        return; // nothing to validate
    }

    // Count existing records for this requester
    var ga = new GlideAggregate(TABLE_NAME);
    ga.addQuery(REQUESTER_FIELD, requester);

    // IMPORTANT:
    // Exclude the current record during updates
    if (!current.isNewRecord()) {
        ga.addQuery('sys_id', '!=', current.getUniqueValue());
    }

    ga.addAggregate('COUNT');
    ga.query();

    var count = 0;
    if (ga.next()) {
        count = parseInt(ga.getAggregate('COUNT'), 10) || 0;
    }

    if (count >= LIMIT) {
        gs.addErrorMessage(
            "Already 7 queries are present for this requester. " +
            "Please delete any previous query then try to create a new one for this requester."
        );
        current.setAbortAction(true); // blocks insert OR update
    }

})(current, previous);
